// Compute an overall sea safety status from a weather snapshot.
// Direction-agnostic — answers "should I be on the water at all?"
// Returns { score: 0-100, level: 'green'|'yellow'|'red'|'black', label: string, reasons: string[] }
function computeSeaStatus(data: {
  windSpeed: number;
  windGusts: number;
  waveHeight: number | null;
  precipitation: number;
  pressure: number;
  cloudCover: number;
}) {
  let score = 100;
  const reasons: string[] = [];

  const wind = data.windSpeed ?? 0;       // knots
  const gusts = data.windGusts ?? 0;      // knots
  const waves = data.waveHeight;           // meters, may be null
  const precip = data.precipitation ?? 0;  // mm
  const pressure = data.pressure ?? 1013;  // hPa

  // --- Instant black triggers: life-threatening conditions ---
  if (wind > 40) {
    // Storm-force winds — no one should be out
    return {
      score: 0,
      level: 'black' as const,
      label: 'Do NOT Go Out',
      reasons: ['Storm-force winds: ' + Math.round(wind) + ' kn']
    };
  }
  if (waves !== null && waves > 5) {
    // Very rough to high seas
    return {
      score: 0,
      level: 'black' as const,
      label: 'Do NOT Go Out',
      reasons: ['Very rough seas: ' + waves.toFixed(1) + 'm waves']
    };
  }

  // --- Wind speed penalties ---
  if (wind > 33) {
    score -= 55;
    reasons.push('Near gale winds: ' + Math.round(wind) + ' kn');
  } else if (wind > 27) {
    score -= 40;
    reasons.push('Strong winds: ' + Math.round(wind) + ' kn');
  } else if (wind > 21) {
    score -= 25;
    reasons.push('Fresh to strong winds: ' + Math.round(wind) + ' kn');
  } else if (wind > 16) {
    score -= 10;
    reasons.push('Moderate winds: ' + Math.round(wind) + ' kn');
  } else if (wind < 5) {
    score -= 5;
    reasons.push('Very light winds: ' + Math.round(wind) + ' kn');
  }

  // --- Gust factor: big difference between sustained and gusts is dangerous ---
  const gustFactor = gusts / Math.max(wind, 1);
  if (gustFactor > 2.0) {
    score -= 20;
    reasons.push('Severe gusts: ' + Math.round(gusts) + ' kn (×' + gustFactor.toFixed(1) + ')');
  } else if (gustFactor > 1.6) {
    score -= 12;
    reasons.push('Strong gusts: ' + Math.round(gusts) + ' kn');
  } else if (gustFactor > 1.3 && gusts > 20) {
    score -= 5;
    reasons.push('Gusty: ' + Math.round(gusts) + ' kn');
  }

  // --- Wave height penalties ---
  if (waves !== null) {
    if (waves > 4) {
      score -= 40;
      reasons.push('Rough seas: ' + waves.toFixed(1) + 'm');
    } else if (waves > 3) {
      score -= 25;
      reasons.push('Rough seas: ' + waves.toFixed(1) + 'm');
    } else if (waves > 2) {
      score -= 15;
      reasons.push('Moderate seas: ' + waves.toFixed(1) + 'm');
    } else if (waves > 1.5) {
      score -= 8;
      reasons.push('Slight seas: ' + waves.toFixed(1) + 'm');
    }
  }

  // --- Precipitation penalties — reduces visibility and comfort ---
  if (precip > 8) {
    score -= 20;
    reasons.push('Heavy precipitation: ' + precip.toFixed(1) + ' mm');
  } else if (precip > 3) {
    score -= 12;
    reasons.push('Moderate precipitation: ' + precip.toFixed(1) + ' mm');
  } else if (precip > 0.5) {
    score -= 5;
    reasons.push('Light precipitation');
  }

  // --- Low pressure penalty — signals storm systems ---
  if (pressure < 990) {
    score -= 15;
    reasons.push('Very low pressure: ' + Math.round(pressure) + ' hPa');
  } else if (pressure < 1000) {
    score -= 8;
    reasons.push('Low pressure: ' + Math.round(pressure) + ' hPa');
  }

  // Clamp score to 0-100
  score = Math.max(0, Math.min(100, score));

  // Map score to tier
  let level: 'green' | 'yellow' | 'red' | 'black';
  let label: string;

  if (score >= 70) {
    level = 'green';
    label = 'Good to Go';
  } else if (score >= 40) {
    level = 'yellow';
    label = 'Caution';
  } else if (score >= 15) {
    level = 'red';
    label = 'Dangerous';
  } else {
    level = 'black';
    label = 'Do NOT Go Out';
  }

  // If no penalties were applied, add a positive note
  if (reasons.length === 0) {
    reasons.push('Conditions look great for sailing');
  }

  return { score, level, label, reasons };
}
